// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "二十一點五十八分。", background: Background.Chapter_4_Ch4_Act16_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不知道自己走了多久。可能十分鐘。可能更久。地下沒有窗戶，看不見天空，只有頭頂壞了一半的螢光燈管和牆上每隔幾公尺出現一次的褪色方向標誌——有些指著「排水泵房」，有些指著「設備間」，有些上面的字已經被水漬模糊到無法辨認。", background: Background.Chapter_4_Ch4_Act16_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他和許星棠、韓越完全失散了。在地下通道的岔路裡，他選了和他們不同的方向。他不知道他們去了哪裡。他甚至不知道他們是不是還在地下。", background: Background.Chapter_4_Ch4_Act16_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他現在站的地方，是一間半封閉的舊資料暫存區。", background: Background.Chapter_4_Ch4_Act16_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這裡不像上面的校史館——沒有玻璃櫃，沒有射燈，沒有展板設計。這裡只是一個被遺忘的角落。牆邊堆著舊展板——木框翹了，布面褪色了，上面還殘留著十年前的展覽標題，字跡被水泡得模糊。金屬架上擺著幾個紙箱，紙箱底部被水泡軟了，歪歪斜斜地坐著，像隨時要塌。地上散落著舊校報底稿、報紙大樣、過期的活動手冊。", background: Background.Chapter_4_Ch4_Act16_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這裡是舊資料暫存區。校史館十年前的東西——搬展時被堆到地下來的。後來地下封了，沒有人再來整理。", background: Background.Chapter_4_Ch4_Act16_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走進去的時候，鞋底踩到了一張紙。紙黏在地上，被水漬浸透了，他撿起來——是一份校報大樣，日期是十五年前。頭版標題關於南翼整修建設。他沒有細看，把紙放回了箱子上。", background: Background.Chapter_4_Ch4_Act16_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他看到了牆角。", background: Background.Chapter_4_Ch4_Act16_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "牆角有一片焦黑。", background: Background.Chapter_4_Ch4_Act16_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是新的焦痕。不是今天、不是昨天、不是今年的。是很舊的。舊到表面已經被新漆蓋了一層，但漆也開始剝了，露出底下黑色的、碳化的牆面。焦痕的面積不大，大約一個人的手臂展開那麼寬，但很深。像這面牆曾經被火舔過，火舌順著牆角向上竄，在牆面和天花板的交界處留下了一道彎曲的、像河流一樣的黑線。", background: Background.Chapter_4_Ch4_Act16_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "焦痕旁邊堆著雜物——舊展板、報廢的燈具、幾塊石膏板。像是有人匆忙地把東西堆在這裡，把焦痕遮住。不是為了隱藏——只是為了不看到。", background: Background.Chapter_4_Ch4_Act16_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）火災。", background: Background.Chapter_4_Ch4_Act16_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）十年前的火。南翼。這裡——地下——也被波及了。", background: Background.Chapter_4_Ch4_Act16_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他蹲下來。手指碰了一下焦痕的邊緣。炭化的牆面在他的指尖下碎了一點，像黑色粉筆的粉末。他縮回手。指尖上是黑的。", background: Background.Chapter_4_Ch4_Act16_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後——不是他想起來的。是畫面自己來的。", background: Background.Chapter_4_Ch4_Act16_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "父親。白襯衫。袖子捲到手肘。濕外套蓋在他頭上。聲音很低。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.GuZe, character: "顧澤", dialogue: "別出聲。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三輪死前看到過的碎片。但這一次，碎片稍微多了一點。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看見了一個女人。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是模糊的輪廓——這次稍微清楚了。矮。瘦。頭髮紮起來。淺灰色的外套。她的雙手抱著一個黑色的、長方形的、有帶子的東西。相機。或者相機包。按在胸口。手指在抽搐。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但這次多了一個細節。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的胸口。工作證。掛在脖子上。塑膠卡套。上面的字——被煙和汗糊了一半，但第一個字是清楚的——", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）許。", background: Background.Chapter_4_Ch4_Act16_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）工作證上寫著——許。", background: Background.Chapter_4_Ch4_Act16_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "碎片斷了。畫面消失了。他又回到了地下暫存區。蹲在焦痕前面。指尖上是黑色的粉末。空氣裡有霉味。螢光燈在閃。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）那個女人姓許。十年前。在校史館附近。抱著相機。手被燒傷了。不鬆手。", background: Background.Chapter_4_Ch4_Act16_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）許星棠的母親——是校內行政職員。十年前火災中死亡。", background: Background.Chapter_4_Ch4_Act16_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）那個女人——是不是她？", background: Background.Chapter_4_Ch4_Act16_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站起來。膝蓋有點僵。他在暫存區裡慢慢走。腳步很輕。他在找什麼——他自己也不確定。但他知道剛才那些碎片不是幻覺。它們是記憶。被壓了十年的、正在慢慢鬆動的記憶。而記憶鬆動的原因就在這裡——在地下，在焦痕旁邊，在十年前被匆忙搬進來、再也沒有人清理的東西裡面。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走到了最裡面的一排金屬架旁邊。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "架子上有一個紙箱。比其他的更舊。更破。底部已經完全被水泡爛了，整個箱子垮在架子上，軟塌塌的，底部已經變成一攤紙漿。箱子旁邊散落著幾張紙——有些是報紙大樣，有些是照片底稿，有些只是空白的備份相紙。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他蹲下來。拿起一張紙。翻過來。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "是一個照片底稿袋。牛皮紙的。舊的。邊角被水泡皺了，上面的字是用老式打字機打的，墨跡已經暈開了，但還能辨認。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "袋子上的標籤寫著：", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「南翼整修後防災演練暨安全說明會／未採用照片」", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）南翼整修後防災演練暨安全說明會。", background: Background.Chapter_4_Ch4_Act16_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這是——今天上午在校史館看到的那張公開照片。同一個活動。同一個名稱。但寫的是——未採用照片。", background: Background.Chapter_4_Ch4_Act16_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）未採用。這張照片不是掛在牆上的那張。是另一張。同一場活動裡拍的、但沒有被選中的照片。", background: Background.Chapter_4_Ch4_Act16_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的手在發抖。不是因為冷。他把袋子打開。裡面有一張照片。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "照片被水氣泡皺了。邊角捲起來。顏色褪了一些。但它是一張完整的照片——比校史館牆上那張更大。更寬。沒有被裁過。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他拿起照片。把它拿到唯一一盞還算亮的螢光燈下面。用手把捲曲的邊角壓平。光落在照片上。", background: Background.Chapter_4_Ch4_Act16_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看見了。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "照片的左側。一個小男孩。穿著小雨衣。大約五六歲。臉圓圓的。頭髮很短。眼睛很亮。他站在一個男人旁邊。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "男人。白襯衫。袖子捲到手肘。手裡拿著一支筆——不是普通的筆，是錄音筆。或者是記事本。在照片裡他正在低頭看手裡的東西，嘴角有一個很淺的、自然的弧度。像一個正在工作、但心情不錯的人。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的臉。年輕。比顧言記憶中更年輕。但五官——鼻子、眼睛、眉骨的弧度——和顧言每天在鏡子裡看到的那個人一模一樣。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）爸。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這是我爸。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）那個小男孩——是我。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的手抖得更厲害了。照片在指尖輕微地晃動。但他不敢放手。他把照片拿得更近。看下一個人。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "照片的中間偏右。一個女人。矮。瘦。頭髮紮低馬尾。淺灰色外套。脖子上掛著相機——黑色的、專業的、比校慶期間學生用的那種更大更重。她的表情很淡。不是冷漠的那種淡——是在控制什麼。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的胸口。工作證。掛帶。塑膠卡套。上面的字比校史館牆上那張公開照片更清楚——因為拍攝角度不同，反光沒有遮住她的臉。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "工作證上寫著：許。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）許。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）和她工作證上的姓——許。和記憶碎片裡的女人——一樣。低馬尾。淺灰色外套。相機。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這個女人。就是記憶裡的那個女人。十年前在火場裡抱著相機、手被燒傷也不鬆手的女人。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她姓許。她是校內行政職員。她——", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她可能就是許星棠的母親。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他強迫自己繼續看。照片的右側邊緣。在另一個位置——比公開照片裡看到的更靠近鏡頭——站著一個人。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個年輕男人。個子不算高。皮膚偏黑。頭髮剪得很短，貼著頭皮弧度。他穿著便裝——不是警服——但站在一個很特殊的位置。他的左邊是兩個穿著施工背心的人——承包商代表。他的右邊是兩個穿著正裝的人——校方行政人員。他站在這兩組人之間。像在維持什麼。像在記錄什麼。不像普通路人。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）年輕的邵叔。十年前的邵叔。他在這張照片裡。站在承包商和校方之間。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）校史館牆上的公開照片裡邵叔站在左邊，離承包商很遠。這張——他離承包商更近。站在他們旁邊。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "照片的背景。一條紅色布條橫掛在牆上。上面的字在公開照片裡只剩「南翼……安全……」幾個字，因為被裁過。但在這張不同的照片裡，構圖更寬，布條上的字是完整的——", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「南翼整修後防災演練暨安全說明會」", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）南翼整修後防災演練暨安全說明會。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）南翼整修。防災演練。安全說明——這不是普通活動。是安全驗收。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的手指壓在照片邊緣。指節發白。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）爸在場。記者。手裡拿著錄音筆。他在採訪南翼的安全問題——不是來放火的。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把照片拿得更近。看下一個人。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）姓許的女人。校內職員。相機。她在記錄。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔。站在承包商和校方之間。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）而我——五六歲的我——也在場。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把照片放下。不是鬆手——是輕輕地、像放下玻璃一樣把它放在紙箱上。然後他蹲在地上。兩手撐著膝蓋。低頭。呼吸很急。不是恐慌的那種急——是大腦裡有太多東西同時衝過來、處理不過來的那種急。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我小時候真的來過這裡。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他閉了一下眼睛。再張開。照片還在。上面的人還在。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）父親和那個姓許的女人認識。那個女人可能就是許星棠的母親。邵叔也在同一張照片裡。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這張照片為什麼被裁掉？為什麼從來沒有人告訴我？", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他蹲在那裡。在地下舊資料暫存區。在焦痕旁邊。在一堆被水泡爛的紙箱和展板之間。他盯著那張照片。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看見了父親的臉。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是證件照的那張——木然的、被定罪的、像一張已經貼上了「縱火犯」標籤的臉。是這張照片裡的臉。自然的。在工作的。嘴角有弧度的。旁邊站著一個小男孩。像一個父親。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）爸。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）你在這裡。你不是被告——你是記者。你拿著錄音筆。你在採訪南翼整修的安全問題。你不是來放火的。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）你是來——", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說不下去了。不是因為詞窮。是因為他不敢把那個詞說出來。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）你是來揭發什麼的。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "二十二點零三分。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他拿起照片。用兩手捧著。像捧著一個會碎的東西。他開始背。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站位。父親在左側。姓許的女職員在中間偏右。邵叔在右側邊緣。承包商代表在邵叔左邊。校方行政人員在邵叔右邊。年幼的自己在父親旁邊。穿小雨衣。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "背景布條。「南翼整修後防災演練暨安全說明會」。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "工作證。「許」。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "父親手裡的東西。錄音筆。或者記事本。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔的位置。靠近承包商和校方。不像普通路人。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）記住。全部記住。下一輪照片會消失——但這一輪，我要把它帶出去。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他再看了一遍。確認每一個人的位置。確認布條上的每一個字。確認工作證上的「許」。確認父親手裡的錄音筆。確認邵叔站在承包商旁邊。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把照片塞回底稿袋。把底稿袋折好，塞進校服內側，靠近胸口的位置。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這張照片不會跟著他回到下一輪。但如果他能活著走出去——至少這一輪，會有人看見它。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）父親。許。相機。邵叔。南翼整修。年幼的我。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）六個關鍵詞。記住。", background: Background.Chapter_4_Ch4_Act16_S3, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站起來。腿有點麻。蹲太久了。他在紙上——不，他沒有紙。他把這些刻在腦子裡。像用刀在骨頭上刻字。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "二十二點零五分。", background: Background.Chapter_4_Ch4_Act16_S3 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他準備離開了。原路返回。從維修門出去。從後門出去。回到地面。", background: Background.Chapter_4_Ch4_Act16_S3 },
];
